/**
 * DistributionChart — Two pie charts side by side using Recharts.
 *
 * Left: Demand type distribution (需求类型分布)
 * Right: Barrier severity distribution (障碍严重度分布)
 */
import React from 'react';
import {
  PieChart,
  Pie,
  Cell,
  Tooltip,
  ResponsiveContainer,
  Legend,
} from 'recharts';
import { Card, CardContent, Typography, Box, useTheme } from '@mui/material';

export interface DistributionData {
  name: string;
  value: number;
}

interface DistributionChartProps {
  demandData: DistributionData[];
  barrierData: DistributionData[];
}

const COLORS = ['#6366F1', '#8B5CF6', '#A78BFA', '#C4B5FD', '#10B981', '#F59E0B', '#EF4444'];

const DistributionChart: React.FC<DistributionChartProps> = ({ demandData, barrierData }) => {
  const theme = useTheme();

  const renderPie = (data: DistributionData[], title: string) => {
    if (data.length === 0) {
      return (
        <Box sx={{ textAlign: 'center', py: 4 }}>
          <Typography variant="body2" color="text.secondary">暂无数据</Typography>
        </Box>
      );
    }

    return (
      <Box sx={{ flex: 1, minWidth: 250 }}>
        <Typography variant="subtitle2" fontWeight={600} align="center" gutterBottom>
          {title}
        </Typography>
        <ResponsiveContainer width="100%" height={260}>
          <PieChart>
            <Pie
              data={data}
              cx="50%"
              cy="50%"
              innerRadius={45}
              outerRadius={90}
              paddingAngle={2}
              dataKey="value"
              nameKey="name"
            >
              {data.map((_, idx) => (
                <Cell
                  key={idx}
                  fill={COLORS[idx % COLORS.length]}
                  stroke={theme.palette.background.paper}
                  strokeWidth={2}
                />
              ))}
            </Pie>
            <Tooltip
              contentStyle={{
                backgroundColor: theme.palette.background.paper,
                border: `1px solid ${theme.palette.divider}`,
                borderRadius: 8,
              }}
            />
          </PieChart>
        </ResponsiveContainer>
      </Box>
    );
  };

  return (
    <Card>
      <CardContent>
        <Typography variant="subtitle1" fontWeight={600} gutterBottom>
          📊 数据分布
        </Typography>
        <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 2 }}>
          {renderPie(demandData, '需求类型分布')}
          {renderPie(barrierData, '障碍严重度分布')}
        </Box>
      </CardContent>
    </Card>
  );
};

export default DistributionChart;
