/**
 * CompetitorChart — Bar chart comparing competitor mention volumes.
 *
 * X-axis: competitor names
 * Y-axis: mention count
 * Each bar with a different color
 * Tooltip with detailed info
 */
import React from 'react';
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  Cell,
} from 'recharts';
import { Card, CardContent, Typography, Box, useTheme } from '@mui/material';

export interface CompetitorDatum {
  name: string;
  mentions: number;
  details?: string;
}

interface CompetitorChartProps {
  data: CompetitorDatum[];
}

const BAR_COLORS = ['#6366F1', '#10B981', '#F59E0B', '#EF4444', '#8B5CF6', '#EC4899', '#06B6D4'];

const CompetitorChart: React.FC<CompetitorChartProps> = ({ data }) => {
  const theme = useTheme();

  if (data.length === 0) {
    return (
      <Card>
        <CardContent>
          <Typography variant="subtitle1" fontWeight={600} gutterBottom>
            竞品声量对比
          </Typography>
          <Box sx={{ textAlign: 'center', py: 6 }}>
            <Typography variant="body2" color="text.secondary">
              暂无竞品数据
            </Typography>
          </Box>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card>
      <CardContent>
        <Typography variant="subtitle1" fontWeight={600} gutterBottom>
          🏢 竞品声量对比
        </Typography>
        <ResponsiveContainer width="100%" height={300}>
          <BarChart data={data} margin={{ top: 5, right: 20, left: 10, bottom: 5 }}>
            <CartesianGrid strokeDasharray="3 3" stroke={theme.palette.divider} />
            <XAxis
              dataKey="name"
              tick={{ fontSize: 12 }}
              stroke={theme.palette.text.secondary}
            />
            <YAxis tick={{ fontSize: 12 }} stroke={theme.palette.text.secondary} />
            <Tooltip
              contentStyle={{
                backgroundColor: theme.palette.background.paper,
                border: `1px solid ${theme.palette.divider}`,
                borderRadius: 8,
              }}
              formatter={(value: number, _name: string, props: { payload: CompetitorDatum }) => {
                const detail = props.payload?.details;
                return detail ? [`${value} 次提及`, detail] : [`${value} 次提及`, '提及次数'];
              }}
            />
            <Bar dataKey="mentions" name="提及次数" radius={[4, 4, 0, 0]}>
              {data.map((_, idx) => (
                <Cell key={idx} fill={BAR_COLORS[idx % BAR_COLORS.length]} />
              ))}
            </Bar>
          </BarChart>
        </ResponsiveContainer>
      </CardContent>
    </Card>
  );
};

export default CompetitorChart;
