/**
 * DashboardPage — Decision desk main page.
 *
 * Features:
 * - Core metric cards: total comments, new this week, confirmed insights, strategy cards
 * - Top 5 recommended actions (from AI agent dashboard output)
 * - Charts: TrendChart, DistributionChart, CompetitorChart
 * - Data from DexieDB (weeklySnapshots + insights)
 * - Auto-creates weekly snapshot on load
 */
import React, { useEffect, useMemo } from 'react';
import {
  Box,
  Typography,
  Card,
  CardContent,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  Chip,
  Alert,
  CircularProgress,
} from '@mui/material';
import LightbulbIcon from '@mui/icons-material/Lightbulb';
import { useBrandStore } from '@/shared/stores/brandStore';
import { db } from '@/shared/db/db';
import { useLiveQuery } from 'dexie-react-hooks';
import { createWeeklySnapshot } from '@/shared/db/snapshot.db';
import MetricsOverview, { type MetricItem } from './MetricsOverview';
import TrendChart, { type TrendDataPoint } from './TrendChart';
import DistributionChart, { type DistributionData } from './DistributionChart';
import CompetitorChart, { type CompetitorDatum } from './CompetitorChart';
import type { Insight } from '@/shared/types/insight';

const DashboardPage: React.FC = () => {
  const currentBrandId = useBrandStore((s) => s.currentBrandId);
  const currentBrand = useBrandStore((s) => {
    const { brands, currentBrandId: cid } = s;
    return brands.find((b) => b.id === cid) ?? null;
  });

  const comments = useLiveQuery(
    () =>
      currentBrandId
        ? db.comments.where({ brandId: currentBrandId }).toArray()
        : Promise.resolve([]),
    [currentBrandId],
  );

  const insights = useLiveQuery(
    () =>
      currentBrandId
        ? db.insights.where({ brandId: currentBrandId }).toArray()
        : Promise.resolve([] as Insight[]),
    [currentBrandId],
  );

  const strategyCards = useLiveQuery(
    () =>
      currentBrandId
        ? db.strategyCards.where({ brandId: currentBrandId }).toArray()
        : Promise.resolve([]),
    [currentBrandId],
  );

  const snapshots = useLiveQuery(
    () =>
      currentBrandId
        ? db.weeklySnapshots.where({ brandId: currentBrandId }).toArray()
        : Promise.resolve([]),
    [currentBrandId],
  );

  // ── Auto-create weekly snapshot on Dashboard load ──
  useEffect(() => {
    if (currentBrandId) {
      createWeeklySnapshot(currentBrandId).catch((err) => {
        console.error('[Dashboard] Failed to create weekly snapshot:', err);
      });
    }
  }, [currentBrandId]);

  // --- Metrics ---
  const metrics: MetricItem[] = useMemo(() => {
    const totalComments = comments?.length ?? 0;
    const confirmedInsights =
      insights?.filter((i) => i.reviewStatus === 'confirmed').length ?? 0;
    const totalStrategies = strategyCards?.length ?? 0;

    // Compute new this week from snapshots
    const sortedSnapshots = [...(snapshots ?? [])].sort(
      (a, b) => new Date(b.weekStart).getTime() - new Date(a.weekStart).getTime(),
    );
    const newestSnapshot = sortedSnapshots[0];
    const previousSnapshot = sortedSnapshots[1];
    const newThisWeek = newestSnapshot?.newComments ?? 0;
    const prevWeekNew = previousSnapshot?.newComments ?? 0;
    const weeklyChange = prevWeekNew > 0 ? ((newThisWeek - prevWeekNew) / prevWeekNew) * 100 : 0;

    return [
      {
        label: '总评论数',
        value: totalComments.toLocaleString(),
        change: undefined,
      },
      {
        label: '本周新增',
        value: newThisWeek.toLocaleString(),
        change: weeklyChange,
        changeLabel: '较上周',
      },
      {
        label: '已确认洞察',
        value: confirmedInsights,
        color: 'success.main',
      },
      {
        label: '策略卡总数',
        value: totalStrategies,
        color: 'primary.main',
      },
    ];
  }, [comments, insights, strategyCards, snapshots]);

  // --- Trend data ---
  const trendData: TrendDataPoint[] = useMemo(() => {
    if (!snapshots || snapshots.length === 0) {
      // Fallback: generate from comments
      if (!comments) return [];
      const byWeek = new Map<string, number>();
      comments.forEach((c) => {
        const d = new Date(c.commentTime || c.importedAt || Date.now());
        const weekStart = getMonday(d).toISOString().split('T')[0];
        byWeek.set(weekStart, (byWeek.get(weekStart) ?? 0) + 1);
      });
      const sorted = [...byWeek.entries()].sort((a, b) => a[0].localeCompare(b[0]));
      let cum = 0;
      return sorted.map(([week, count]) => {
        cum += count;
        return { week, cumulative: cum, newComments: count };
      });
    }

    const sorted = [...snapshots].sort((a, b) => a.weekStart.localeCompare(b.weekStart));
    let cum = 0;
    return sorted.map((s) => {
      cum += s.newComments;
      return {
        week: s.weekStart,
        cumulative: Math.max(cum, s.totalComments),
        newComments: s.newComments,
      };
    });
  }, [snapshots, comments]);

  // --- Distribution data ---
  const { demandData, barrierData } = useMemo(() => {
    if (!insights) return { demandData: [], barrierData: [] };

    const demandCounts = new Map<string, number>();
    const barrierCounts = new Map<string, number>();

    insights
      .filter((i) => i.reviewStatus === 'confirmed')
      .forEach((ins) => {
        if (ins.type === 'demand') {
          const cat = (ins as any).category ?? '其他需求';
          demandCounts.set(cat, (demandCounts.get(cat) ?? 0) + 1);
        } else if (ins.type === 'barrier') {
          const sev = (ins as any).severity ?? 'medium';
          const label = sev === 'high' ? '高严重度' : sev === 'medium' ? '中严重度' : '低严重度';
          barrierCounts.set(label, (barrierCounts.get(label) ?? 0) + 1);
        }
      });

    return {
      demandData: [...demandCounts.entries()].map(([name, value]) => ({ name, value })),
      barrierData: [...barrierCounts.entries()].map(([name, value]) => ({ name, value })),
    };
  }, [insights]);

  // --- Competitor data ---
  const competitorData: CompetitorDatum[] = useMemo(() => {
    if (!insights) return [];
    const compCounts = new Map<string, number>();
    insights
      .filter((i) => i.type === 'competitor' && i.reviewStatus === 'confirmed')
      .forEach((ins) => {
        const name = (ins as any).competitorName ?? '未知竞品';
        compCounts.set(name, (compCounts.get(name) ?? 0) + 1);
      });

    const comps = currentBrand?.competitors ?? [];
    // Merge with brand competitors
    comps.forEach((c) => {
      if (!compCounts.has(c.name)) compCounts.set(c.name, 0);
    });

    return [...compCounts.entries()]
      .sort((a, b) => b[1] - a[1])
      .map(([name, mentions]) => ({ name, mentions }));
  }, [insights, currentBrand]);

  // --- Top 5 actions from strategy cards ---
  const topActions = useMemo(() => {
    if (!strategyCards) return [];
    return strategyCards
      .filter((s) => s.reviewStatus === 'confirmed')
      .sort((a, b) => {
        const pOrder: Record<string, number> = { P0: 0, P1: 1, P2: 2 };
        return (pOrder[a.priority] ?? 3) - (pOrder[b.priority] ?? 3);
      })
      .slice(0, 5);
  }, [strategyCards]);

  if (!currentBrandId) {
    return (
      <Box sx={{ p: 4, textAlign: 'center' }}>
        <Alert severity="info">请先在顶部选择一个品牌</Alert>
      </Box>
    );
  }

  const isLoading =
    comments === undefined ||
    insights === undefined ||
    strategyCards === undefined ||
    snapshots === undefined;

  if (isLoading) {
    return (
      <Box sx={{ display: 'flex', justifyContent: 'center', py: 8 }}>
        <CircularProgress />
      </Box>
    );
  }

  return (
    <Box sx={{ p: 3, height: '100%', overflow: 'auto' }}>
      {/* Header */}
      <Box sx={{ mb: 3 }}>
        <Typography variant="h5" fontWeight={700} gutterBottom>
          📊 {currentBrand?.name ?? ''} 决策台
        </Typography>
        <Typography variant="body2" color="text.secondary">
          核心指标总览与数据洞察
        </Typography>
      </Box>

      {/* Metrics cards */}
      <MetricsOverview metrics={metrics} />

      {/* Top 5 Actions + Trend Chart */}
      <Box
        sx={{
          display: 'grid',
          gridTemplateColumns: { xs: '1fr', lg: '1fr 2fr' },
          gap: 2,
          mb: 2,
        }}
      >
        {/* Recommended actions */}
        <Card>
          <CardContent>
            <Typography variant="subtitle1" fontWeight={600} gutterBottom>
              💡 Top 5 本周建议动作
            </Typography>
            {topActions.length === 0 ? (
              <Box sx={{ textAlign: 'center', py: 4 }}>
                <LightbulbIcon sx={{ fontSize: 40, color: 'text.disabled', mb: 1 }} />
                <Typography variant="body2" color="text.secondary">
                  暂无策略建议，请先确认策略卡
                </Typography>
              </Box>
            ) : (
              <List dense>
                {topActions.map((action, idx) => (
                  <ListItem key={action.id} sx={{ px: 0 }}>
                    <ListItemIcon sx={{ minWidth: 28 }}>
                      <Chip
                        label={action.priority}
                        size="small"
                        color={
                          action.priority === 'P0'
                            ? 'error'
                            : action.priority === 'P1'
                              ? 'warning'
                              : 'primary'
                        }
                        sx={{ fontWeight: 700, height: 20, fontSize: 10 }}
                      />
                    </ListItemIcon>
                    <ListItemText
                      primary={action.title}
                      secondary={
                        action.contentDirection
                          ? action.contentDirection.substring(0, 60) + '...'
                          : ''
                      }
                      primaryTypographyProps={{ variant: 'body2', fontWeight: 500 }}
                      secondaryTypographyProps={{ variant: 'caption' }}
                    />
                  </ListItem>
                ))}
              </List>
            )}
          </CardContent>
        </Card>

        {/* Trend Chart */}
        <TrendChart data={trendData} />
      </Box>

      {/* Distribution + Competitor */}
      <Box
        sx={{
          display: 'grid',
          gridTemplateColumns: { xs: '1fr', lg: '1fr 1fr' },
          gap: 2,
        }}
      >
        <DistributionChart demandData={demandData} barrierData={barrierData} />
        <CompetitorChart data={competitorData} />
      </Box>
    </Box>
  );
};

/** Get the Monday of the week for a given date */
function getMonday(d: Date): Date {
  const date = new Date(d);
  const day = date.getDay();
  const diff = day === 0 ? -6 : 1 - day;
  date.setDate(date.getDate() + diff);
  date.setHours(0, 0, 0, 0);
  return date;
}

export default DashboardPage;
