/**
 * MetricsOverview — 4 core metric cards in a row.
 *
 * Displays: Total comments, new this week, confirmed insights, strategy cards count.
 * Each card shows the metric value, label, and YoY change arrow indicator.
 */
import React from 'react';
import { Card, CardContent, Typography, Box } from '@mui/material';
import TrendingUpIcon from '@mui/icons-material/TrendingUp';
import TrendingDownIcon from '@mui/icons-material/TrendingDown';
import TrendingFlatIcon from '@mui/icons-material/TrendingFlat';

export interface MetricItem {
  label: string;
  value: string | number;
  change?: number; // percentage change, e.g. 12.5 means +12.5%
  changeLabel?: string;
  color?: string;
}

interface MetricsOverviewProps {
  metrics: MetricItem[];
}

const MetricsOverview: React.FC<MetricsOverviewProps> = ({ metrics }) => {
  return (
    <Box
      sx={{
        display: 'grid',
        gridTemplateColumns: {
          xs: '1fr',
          sm: '1fr 1fr',
          md: 'repeat(4, 1fr)',
        },
        gap: 2,
        mb: 3,
      }}
    >
      {metrics.map((m, idx) => (
        <Card
          key={idx}
          sx={{
            bgcolor: 'background.paper',
            border: '1px solid',
            borderColor: 'divider',
          }}
        >
          <CardContent sx={{ py: 2, px: 2.5, '&:last-child': { pb: 2 } }}>
            <Typography variant="caption" color="text.secondary" sx={{ textTransform: 'uppercase', letterSpacing: 0.5 }}>
              {m.label}
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ my: 0.5, color: m.color ?? 'text.primary' }}>
              {m.value}
            </Typography>
            {m.change !== undefined && (
              <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                {m.change > 0 ? (
                  <TrendingUpIcon fontSize="small" color="success" />
                ) : m.change < 0 ? (
                  <TrendingDownIcon fontSize="small" color="error" />
                ) : (
                  <TrendingFlatIcon fontSize="small" color="disabled" />
                )}
                <Typography
                  variant="caption"
                  color={m.change > 0 ? 'success.main' : m.change < 0 ? 'error.main' : 'text.secondary'}
                  fontWeight={600}
                >
                  {m.change > 0 ? '▲' : m.change < 0 ? '▼' : '—'} {Math.abs(m.change).toFixed(1)}%
                </Typography>
                {m.changeLabel && (
                  <Typography variant="caption" color="text.disabled">
                    {m.changeLabel}
                  </Typography>
                )}
              </Box>
            )}
          </CardContent>
        </Card>
      ))}
    </Box>
  );
};

export default MetricsOverview;
