import { db } from './db';
import type { WeeklySnapshot } from '../types/strategy';

/** Get all snapshots for a brand */
export async function getSnapshotsByBrand(brandId: string): Promise<WeeklySnapshot[]> {
  return db.weeklySnapshots.where({ brandId }).toArray();
}

/** Get snapshot by brand and week start date */
export async function getSnapshotByWeek(
  brandId: string,
  weekStart: string,
): Promise<WeeklySnapshot | undefined> {
  return db.weeklySnapshots.where({ brandId, weekStart }).first();
}

/** Put a weekly snapshot */
export async function putSnapshot(snapshot: WeeklySnapshot): Promise<void> {
  await db.weeklySnapshots.put(snapshot);
}

/** Bulk put snapshots */
export async function bulkPutSnapshots(snapshots: WeeklySnapshot[]): Promise<void> {
  await db.weeklySnapshots.bulkPut(snapshots);
}

/** Get Monday 00:00:00 of the week containing `d` */
export function getWeekStart(d: Date): Date {
  const date = new Date(d);
  const day = date.getDay();
  const diff = day === 0 ? -6 : 1 - day;
  date.setDate(date.getDate() + diff);
  date.setHours(0, 0, 0, 0);
  return date;
}

/** Get the start of the previous week relative to a given date */
function getLastWeekStart(d: Date): Date {
  const ws = getWeekStart(d);
  ws.setDate(ws.getDate() - 7);
  return ws;
}

/**
 * Auto-create a weekly snapshot for a brand if one doesn't already exist
 * for the current week. Idempotent — safe to call on every Dashboard load.
 */
export async function createWeeklySnapshot(brandId: string): Promise<WeeklySnapshot | null> {
  const weekStart = getWeekStart(new Date());
  const weekStartStr = weekStart.toISOString();

  // Check if this week's snapshot already exists
  const existing = await db.weeklySnapshots
    .where({ brandId, weekStart: weekStartStr })
    .first();
  if (existing) return null;

  const [comments, insights, cards] = await Promise.all([
    db.comments.where({ brandId }).toArray(),
    db.insights.where({ brandId }).and((i) => i.reviewStatus === 'confirmed').toArray(),
    db.strategyCards.where({ brandId }).toArray(),
  ]);

  const lastWeekStart = getLastWeekStart(weekStart);
  const newComments = comments.filter((c) => {
    const ts = c.importedAt || c.commentTime || '';
    if (!ts) return false;
    return new Date(ts).getTime() >= lastWeekStart.getTime();
  });

  const snapshot: WeeklySnapshot = {
    id: `snap_${brandId}_${weekStartStr.split('T')[0]}`,
    brandId,
    weekStart: weekStartStr,
    totalComments: comments.length,
    newComments: newComments.length,
    confirmedInsights: insights.length,
    strategyCards: cards.length,
    metrics: {},
  };

  await db.weeklySnapshots.put(snapshot);
  console.log(
    `[Snapshot] Created weekly snapshot for brand=${brandId}: ` +
    `${snapshot.totalComments} total, ${snapshot.newComments} new, ` +
    `${snapshot.confirmedInsights} insights, ${snapshot.strategyCards} cards`,
  );
  return snapshot;
}
